// Decisions.jsx
import React, { useEffect, useState } from "react";

/*
  Decisions.jsx
  Enterprise-grade Replacement Decisions page
  Rendered INSIDE AdminLayout (page content only)
*/

// --------------------------------------------------
// DUMMY DATA (REQUIRED — replaces backend ML API)
// --------------------------------------------------
const DUMMY_REQUESTS = [
  {
    id: "REQ-2026-001",
    systemId: "SYS-8472",
    owner: "Manufacturing / Line B",
    aiVerdict: "approve",
    confidence: 94,
    status: "pending",
    systemSnapshot: {
      ageYears: 4,
      warrantyUntil: null,
    },
    timeline: [
      { action: "Requested replacement" },
      { action: "AI verdict generated" },
    ],
  },
  {
    id: "REQ-2026-002",
    systemId: "SYS-9031",
    owner: "Finance / Analytics",
    aiVerdict: "reject",
    confidence: 78,
    status: "pending",
    systemSnapshot: {
      ageYears: 2,
      warrantyUntil: "2027-08-01",
    },
    timeline: [
      { action: "Requested replacement" },
      { action: "AI ruled out hardware failure" },
    ],
  },
];

// --------------------------------------------------
// Component
// --------------------------------------------------
export default function Decisions() {
  const [requests, setRequests] = useState(DUMMY_REQUESTS);
  const [selected, setSelected] = useState(null);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [actionMode, setActionMode] = useState(null);
  const [actionReason, setActionReason] = useState("");

  // Lock background scroll when drawer open
  useEffect(() => {
    document.body.style.overflow = drawerOpen ? "hidden" : "auto";
    return () => (document.body.style.overflow = "auto");
  }, [drawerOpen]);

  const openDrawer = (req, mode = null) => {
    setSelected(req);
    setActionMode(mode);
    setActionReason("");
    setDrawerOpen(true);
  };

  const closeDrawer = () => {
    setDrawerOpen(false);
    setSelected(null);
    setActionMode(null);
    setActionReason("");
  };

  const submitDecision = () => {
    if (!actionReason || actionReason.length < 5) {
      alert("Please provide a valid decision note.");
      return;
    }
    console.log("Decision submitted:", actionMode, actionReason);
    closeDrawer();
  };

  return (
    <div className="p-6 bg-gray-50 min-h-[calc(100vh-4rem)]">
      {/* Header */}
      <div className="mb-6">
        <h1 className="text-2xl font-semibold text-slate-900">
          Replacement Decisions
        </h1>
        <p className="text-sm text-slate-600">
          AI-verified hardware replacement approvals
        </p>
      </div>

      {/* Table */}
      <div className="bg-white border rounded-lg shadow overflow-hidden">
        <table className="min-w-full divide-y">
          <thead className="bg-gray-50 text-xs uppercase text-gray-600">
            <tr>
              <th className="px-4 py-3 text-left">Request</th>
              <th className="px-4 py-3 text-left">System</th>
              <th className="px-4 py-3 text-left">Owner</th>
              <th className="px-4 py-3 text-left">AI Verdict</th>
              <th className="px-4 py-3 text-right">Confidence</th>
              <th className="px-4 py-3 text-left">Action</th>
            </tr>
          </thead>

          <tbody className="divide-y">
            {requests.map((r) => (
              <tr key={r.id} className="hover:bg-gray-50">
                <td className="px-4 py-3 font-medium text-sky-600">
                  <button onClick={() => openDrawer(r)}>
                    {r.id}
                  </button>
                </td>
                <td className="px-4 py-3">{r.systemId}</td>
                <td className="px-4 py-3">{r.owner}</td>
                <td className="px-4 py-3">
                  <span
                    className={`px-2 py-1 rounded-full text-xs ${
                      r.aiVerdict === "approve"
                        ? "bg-green-50 text-green-700"
                        : "bg-red-50 text-red-700"
                    }`}
                  >
                    {r.aiVerdict.toUpperCase()}
                  </span>
                </td>
                <td className="px-4 py-3 text-right">{r.confidence}%</td>
                <td className="px-4 py-3">
                  <div className="flex gap-2">
                    <button
                      onClick={() => openDrawer(r)}
                      className="px-3 py-1 border rounded-md text-sm"
                    >
                      Review
                    </button>
                    <button
                      onClick={() => openDrawer(r, "approve")}
                      className="px-3 py-1 bg-green-600 text-white rounded-md text-sm"
                    >
                      Quick Approve
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Drawer */}
      {drawerOpen && selected && (
        <div className="fixed inset-0 z-50">
          <div
            className="absolute inset-0 bg-black/40"
            onClick={closeDrawer}
          />

          <aside
            className="absolute right-0 top-0 h-full w-full sm:w-[720px] bg-white shadow-2xl overflow-y-auto"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="p-5 border-b flex justify-between">
              <div>
                <div className="text-xs text-slate-500">Decision Review</div>
                <div className="text-lg font-semibold">
                  {selected.id} — {selected.systemId}
                </div>
              </div>
              <button
                onClick={closeDrawer}
                className="px-3 py-1 bg-slate-100 rounded-md text-sm"
              >
                Close
              </button>
            </div>

            <div className="p-5 space-y-6">
              <section>
                <h3 className="text-sm font-semibold mb-2">System Snapshot</h3>
                <div className="bg-gray-50 rounded-md p-4 text-sm">
                  <div>Age: {selected.systemSnapshot.ageYears} years</div>
                  <div>
                    Warranty:{" "}
                    {selected.systemSnapshot.warrantyUntil
                      ? "Active"
                      : "Expired"}
                  </div>
                </div>
              </section>

              <section>
                <h3 className="text-sm font-semibold mb-2">Final Decision</h3>
                <div className="bg-white border rounded-md p-4 space-y-3">
                  <div className="flex gap-2">
                    <button
                      onClick={() => setActionMode("approve")}
                      className="px-3 py-2 bg-green-600 text-white rounded-md text-sm"
                    >
                      Approve
                    </button>
                    <button
                      onClick={() => setActionMode("reject")}
                      className="px-3 py-2 bg-red-50 text-red-700 rounded-md text-sm border"
                    >
                      Reject
                    </button>
                  </div>

                  {actionMode && (
                    <>
                      <textarea
                        value={actionReason}
                        onChange={(e) => setActionReason(e.target.value)}
                        placeholder="Decision note (required)"
                        className="w-full border rounded-md p-2 min-h-[90px]"
                      />
                      <div className="flex justify-end gap-2">
                        <button
                          onClick={() => setActionMode(null)}
                          className="px-3 py-2 border rounded-md text-sm"
                        >
                          Cancel
                        </button>
                        <button
                          onClick={submitDecision}
                          className="px-3 py-2 bg-sky-600 text-white rounded-md text-sm"
                        >
                          Submit
                        </button>
                      </div>
                    </>
                  )}
                </div>
              </section>
            </div>
          </aside>
        </div>
      )}
    </div>
  );
}
